  ('heelevel3-7ec62a85-moex-00086', 'heelevel3-7ec62a85', 'heelevel3-7ec62a85-moex-113-3a7b2121', 'sub-heelevel3-7ec62a85-02', NULL, 'single_choice', '非營利組織與公司進行跨界合作有多種模式，由公司另行創造一個非營利實體，並透過該實體來 管理公司的慈善目標，係屬於下列那一種模式？', '["參與型贊助（jointissuepromotions）", "以交易為基礎的贊助（transaction-basedpromotions）", "公司基金會（corporatefoundations）", "合資（jointventures）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:20+00:00", "source_pdf_sha1": "3c5fbab47917", "answer_pdf_sha1": "ea9f06b2527a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "325", "s": "0303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('heelevel3-7ec62a85-moex-00087', 'heelevel3-7ec62a85', 'heelevel3-7ec62a85-moex-113-3a7b2121', 'sub-heelevel3-7ec62a85-02', NULL, 'single_choice', '有關民眾參與的困境，下列敘述何者錯誤？', '["數位落差可能導致特定群體逐漸被排除於公共政策參與過程之外", "因社群媒體的興起，造成民眾公共參與管道大幅限縮", "部分政府官員為求快速展現績效，會視民眾參與為畏途", "若民眾在參與時缺乏民主素養，只依賴情緒而非理性，容易形成民粹政治"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:20+00:00", "source_pdf_sha1": "3c5fbab47917", "answer_pdf_sha1": "ea9f06b2527a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "325", "s": "0303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('heelevel3-7ec62a85-moex-00088', 'heelevel3-7ec62a85', 'heelevel3-7ec62a85-moex-113-3a7b2121', 'sub-heelevel3-7ec62a85-02', NULL, 'single_choice', '「社會發展計畫由國家發展委員會會同財政部、行政院主計總處及相關機關審議後報行政院核 定。」以上敘述符合何種概念？', '["財主關係", "跨域治理", "公私合夥", "群眾外包"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:20+00:00", "source_pdf_sha1": "3c5fbab47917", "answer_pdf_sha1": "ea9f06b2527a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "325", "s": "0303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('heelevel3-7ec62a85-moex-00089', 'heelevel3-7ec62a85', 'heelevel3-7ec62a85-moex-113-3082b5f1', 'sub-heelevel3-7ec62a85-03', NULL, 'essay', '某甲因於臺北市工作，因此於文山區考試院附近，向房東某乙租賃頂樓
加蓋房屋一間供居住，因屬違建不具房屋稅稅籍，111 年 8 月 1 日向內
政部線上申請 3百億元中央擴大租金補貼專案計畫補貼，內政部審查通
過並於 111 年 9月 1 日起每月領有 3600元租金補貼。但112 年 5月 1 日
時內政部清查後發現，某甲所租的房屋未具房屋稅稅籍，因此不符合 111
年 8 月某甲申請時之「三百億元中央擴大租金補貼專案計畫補貼作業規
定」的規定。就此，內政部可否撤銷該補貼，而當事人會申請補貼乃因為
工作所得不佳，家庭環境不好，因此無法負擔臺北市高額房租，且已經領
取之房租補貼已繳交給房東，無法返還，請問內政部有無可以解決的方
式？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:20+00:00", "source_pdf_sha1": "8dd560c3a46d", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "325", "s": "0403", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('heelevel3-7ec62a85-moex-00090', 'heelevel3-7ec62a85', 'heelevel3-7ec62a85-moex-113-3082b5f1', 'sub-heelevel3-7ec62a85-03', NULL, 'essay', 'A長照機構與 B直轄市政府衛生局（下稱 B衛生局）簽有「B直轄市特
約長期照顧家庭照顧者喘息服務行政契約書」（下稱行政契約），提供相
關喘息服務，行政契約中有 A長照機構依行政程序法第 148條自願接受
執行之約定。B衛生局發現 A長照機構有虛報費用之情事，依行政契約
之約定可處虛報費用金額 10 倍之違約金，合計新臺幣 50 萬元。B衛生
局遂限期通知甲繳納，催繳函並有「若逾期不履行，本局依法移送行政
執行分署強制執行」之記載。假設A長照機構甲逾期仍未繳還公費，B衛
生局得否以催繳函為執行名義移送該管行政執行分署強制執行？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:20+00:00", "source_pdf_sha1": "8dd560c3a46d", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "325", "s": "0403", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('heelevel3-7ec62a85-moex-00091', 'heelevel3-7ec62a85', 'heelevel3-7ec62a85-moex-113-3082b5f1', 'sub-heelevel3-7ec62a85-03', NULL, 'single_choice', '關於依法行政之敘述，下列何者錯誤？', '["執行法律之細節性、技術性次要事項，由行政機關發布命令為必要之規範，不違反法律保留原則", "法律優位原則又稱為消極的依法行政原則", "給付行政措施，只要預算允許，即無須適用法律保留原則", "對於人民違反行政法上義務之裁罰，其處罰之構成要件，應以法律或法律明確授權之命令定之 31750"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:20+00:00", "source_pdf_sha1": "8dd560c3a46d", "answer_pdf_sha1": "501740119b54", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "325", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('heelevel3-7ec62a85-moex-00092', 'heelevel3-7ec62a85', 'heelevel3-7ec62a85-moex-113-3082b5f1', 'sub-heelevel3-7ec62a85-03', NULL, 'single_choice', '依司法院大法官解釋意旨，關於信賴保護原則所需衡酌之事項，不包括下列何者？', '["法秩序變動所追求之政策目的", "國家財政負擔之能力", "修法過程中可決票數之多寡", "值得保護之信賴利益的輕重"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:20+00:00", "source_pdf_sha1": "8dd560c3a46d", "answer_pdf_sha1": "501740119b54", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "325", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法律廉政"}'::jsonb, NULL),
