  ('heelevel3-7ec62a85-moex-00094', 'heelevel3-7ec62a85', 'heelevel3-7ec62a85-moex-113-3082b5f1', 'sub-heelevel3-7ec62a85-03', NULL, 'single_choice', '關於地方自治，下列敘述何者正確？', '["基於地方自治，中央不得要求地方分擔全民健保保險費之補助", "關於自治事項，地方不得以自治法規另定較中央法規更高之限制標準", "地方自治條例與中央法規牴觸者，中央主管機關應起訴請求行政法院判決自治條例無效", "地方自治團體應作為而不作為而危害公益，中央機關於情形急迫時得代行處理"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:20+00:00", "source_pdf_sha1": "8dd560c3a46d", "answer_pdf_sha1": "501740119b54", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "325", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法律廉政"}'::jsonb, NULL),
